  ('dietitian-moex-00296', 'dietitian', 'dietitian-moex-113-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '欲符合衛生福利部每日飲食指南手冊所建議之「以未精製全穀取代精製穀類」比例，於120公克的穀類中應包 含多少公克未精製全穀類？', '["60公克", "40公克", "30公克", "20公克"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "c45c95a48c64", "answer_pdf_sha1": "bd487c67e87b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "55", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
