  ('dietitian-moex-00298', 'dietitian', 'dietitian-moex-113-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有關國內外老人營養相關計畫與服務的現況，下列敘述何者正確？', '["美國The Older American Act（OAA）法案，保障聯邦政府分配專案經費給州政府，提供65歲以上老人支持 性服務，主管機關為Administration on Aging（AOA）", "美國The Older American Act（OAA）法案對於不同層級的老人社群之需求，設計不同的社區營養計畫，例 如：對於有行動力而需生活支援的老年人給予定點聚集式的餐食供應，對於行動不便者則採取送餐到家的 服務", "我國的老人營養計畫或服務發展雖較晚，但開辦時即兼顧醫療、金錢補助及餐食相關服務", "我國的長期照護體系在醫院附屬的養護中心是由醫院營養師採兼職模式運作，非醫院的長照機構在設置規 範中則有要求配置營養師"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "c45c95a48c64", "answer_pdf_sha1": "bd487c67e87b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "55", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00299', 'dietitian', 'dietitian-moex-113-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '各類老齡社會之人口比例定義，下列敘述何者錯誤？', '["65歲以上人口占總人口比率達7%稱為「高齡化社會」（aging society）", "65歲以上人口占總人口比率達14%稱為「高齡社會」（aged society）", "65歲以上人口占總人口比率達21%稱為「超高齡社會」（super-aged society）", "65歲以上人口視為老年人口"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "c45c95a48c64", "answer_pdf_sha1": "bd487c67e87b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "55", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00300', 'dietitian', 'dietitian-moex-113-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依據「學校午餐食物內容及營養基準」階段值，下列何者不適合？', '["可提供低糖的綠豆薏仁湯", "提高豆製品食物供應，可作為主菜、副菜", "提高魚類供應，但不建議油炸", "每日至少都有1種以上蔬菜"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "c45c95a48c64", "answer_pdf_sha1": "bd487c67e87b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "55", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00301', 'dietitian', 'dietitian-moex-113-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依據民國107年之素食飲食指南手冊建議，以每日2,000大卡為基準，下列敘述何者錯誤？', '["奶素與奶蛋素人口，每日均建議攝取1.5份乳品類", "所有素食者，每日均建議攝取1份以上鈣質較高的豆製品，如豆乾、傳統豆腐", "所有素食者，每日均建議攝取1份堅果種子類", "吃全素者，每日應攝取4份蔬菜，2份水果"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "c45c95a48c64", "answer_pdf_sha1": "bd487c67e87b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "55", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00302', 'dietitian', 'dietitian-moex-113-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依據教育部校園飲品及點心販售規範，下列那項產品不得於國中員生消費合作社販售？', '["一份脂肪占總熱量10%的保久乳", "一份含糖量占總熱量12%的優酪乳", "一份含糖量占總熱量10%以上的豆漿", "一份300大卡但不含反式脂肪酸的麵包"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "c45c95a48c64", "answer_pdf_sha1": "bd487c67e87b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "55", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
